/// Result of a visitor callback.
///
/// Allows visitors to control the conversion flow by either proceeding
/// with default behavior, providing custom output, skipping elements,
/// preserving HTML, or signaling errors.
public enum VisitResult: Codable, Sendable, Hashable {
    /// Continue with default conversion behavior
    case `continue`
    /// Replace default output with custom markdown
    ///
    /// The visitor takes full responsibility for the markdown output
    /// of this node and its children.
    case custom(field0: String)
    /// Skip this element entirely (don't output anything)
    ///
    /// The element and all its children are ignored in the output.
    case skip
    /// Preserve original HTML (don't convert to markdown)
    ///
    /// The element's raw HTML is included verbatim in the output.
    case preserveHtml
    /// Stop conversion with an error
    ///
    /// The conversion process halts and returns this error message.
    case error(field0: String)
}

/// Errors that can occur during HTML to Markdown conversion.
public enum ConversionError: Swift.Error {
    /// HTML parsing error
    case parseError(message: String, field0: String)
    /// HTML sanitization error
    case sanitizationError(message: String, field0: String)
    /// Invalid configuration
    case configError(message: String, field0: String)
    /// I/O error — stores the error message string so the variant is FFI-safe.
    ///
    /// Use `ConversionError::from(io_error)` to convert from `std::io::Error`.
    case ioError(message: String, field0: String)
    /// Panic caught during conversion to prevent unwinding across FFI boundaries
    case panic(message: String, field0: String)
    /// Invalid input data
    case invalidInput(message: String, field0: String)
    /// Generic conversion error
    case other(message: String, field0: String)
    /// Synthetic case raised when a Rust serde unit-enum raw value cannot
    /// be mapped to a known Swift case during DTO unmarshaling.
    case validation(message: String, source: String)
}

// MARK: - JSON-String Convenience Overloads
// These overloads accept JSON-encoded config parameters and decode them automatically.
// Enables e2e tests to pass JSON strings directly without typed config construction.

/// Resolves a string argument as either a file path or literal UTF-8 content.
/// Searches: current working directory, ALEF_TEST_DOCUMENTS_DIR env var,
/// and ancestor `test_documents/` or `fixtures/` directories (up to 16 levels).
/// If no file is found, treats the string as UTF-8 content and returns its bytes.
private func _loadBytesFromPathOrUtf8(_ pathOrContent: String) throws -> [UInt8] {
    let fm = FileManager.default
    var roots: [String] = [fm.currentDirectoryPath]
    if let envRoot = ProcessInfo.processInfo.environment["ALEF_TEST_DOCUMENTS_DIR"] {
        roots.append(envRoot)
    }
    var walker = URL(fileURLWithPath: fm.currentDirectoryPath)
    for _ in 0..<16 {
        roots.append(walker.appendingPathComponent("test_documents").path)
        roots.append(walker.appendingPathComponent("fixtures").path)
        let parent = walker.deletingLastPathComponent()
        if parent.path == walker.path { break }
        walker = parent
    }
    let candidates = [pathOrContent] + roots.map { ($0 as NSString).appendingPathComponent(pathOrContent) }
    for path in candidates {
        if fm.fileExists(atPath: path), let data = try? Data(contentsOf: URL(fileURLWithPath: path)) {
            return [UInt8](data)
        }
    }
    return [UInt8](pathOrContent.utf8)
}

public func convert(_ html: String, _ optionsJson: String) throws -> ConversionResult {
    let options = try conversionOptionsFromJson(optionsJson)
