/// Serialise a `VisitResult` to a JSON string matching Rust serde defaults.
private func visit_result_toJson(_ result: VisitResult) -> String {
    switch result {
    case .`continue`: return "\"Continue\""
    case .custom(let v): return "{\"Custom\":\"\(jsonEscapeStr(v))\"}"
    case .skip: return "\"Skip\""
    case .preserveHtml: return "\"PreserveHtml\""
    case .error(let v): return "{\"Error\":\"\(jsonEscapeStr(v))\"}"
    }
}

/// Escape a Swift String for embedding in a JSON string literal.
private func jsonEscapeStr(_ s: String) -> String {
    s.replacingOccurrences(of: "\\", with: "\\\\")
     .replacingOccurrences(of: "\"", with: "\\\"")
     .replacingOccurrences(of: "\n", with: "\\n")
     .replacingOccurrences(of: "\r", with: "\\r")
     .replacingOccurrences(of: "\t", with: "\\t")
}

/// Wrap a `HtmlVisitorProtocol` conformer in an opaque `VisitorHandle` handle
/// that can be passed to `conversionOptionsFromJsonWithVisitor(...)` on the Rust side.
public func makeHtmlVisitorHandle(_ visitor: any HtmlVisitorProtocol) -> VisitorHandle {
    return RustBridge.makeHtmlVisitorHandle(SwiftHtmlVisitorBox(_HtmlVisitorProtocolAdapter(visitor)))
}

/// Decode `ConversionOptions` JSON and attach a `VisitorHandle` visitor handle.
/// Forwards to the swift-bridge shim emitted in the `RustBridge` module —
/// re-exposed here so callers do not need `import RustBridge`.
public func conversionOptionsFromJsonWithVisitor(_ json: String, _ visitor: VisitorHandle?) throws -> ConversionOptions {
    return try RustBridge.conversionOptionsFromJsonWithVisitor(json, visitor)
}

// MARK: - Free-function Forwarders
// Re-export every public free function on the source Rust crate as a
// top-level `public func` on the host module so consumers do not need to
// `import RustBridge` directly. Forwarders take Swift-native parameter
// types and convert to the swift-bridge runtime types internally.

/// Convert HTML to Markdown, Djot, or plain text.
///
/// Returns a [`ConversionResult`] with converted content plus optional metadata,
/// document structure, table data, inline images, and warnings depending on the
/// enabled features and conversion options.
///
/// # Arguments
///
/// * `html` — the HTML string to convert.
/// * `options` — conversion options. Rust accepts bare [`ConversionOptions`],
///   `Some(options)`, or `None`. Language bindings expose the same option
///   fields through native constructors or optional parameters.
///
/// # Example
///
/// ```
/// use html_to_markdown_rs::{convert, ConversionOptions};
///
/// let html = "<h1>Hello World</h1>";
///
/// // Bare options — most ergonomic.
/// let result = convert(html, ConversionOptions::default()).unwrap();
/// assert!(result.content.as_deref().unwrap_or("").contains("Hello World"));
///
/// // `None` falls back to defaults.
/// let result = convert(html, None).unwrap();
/// assert!(result.content.as_deref().unwrap_or("").contains("Hello World"));
/// ```
///
/// # Errors
///
/// Returns an error if HTML parsing fails or if the input contains invalid UTF-8.
public func convert(html: String, options: ConversionOptions? = nil) throws -> ConversionResult {
        let _rb_html = RustString(html)
    return try RustBridge.convert(_rb_html, options)
}
